import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

function HomePage() {
  const [videos, setVideos] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios.get('http://localhost:8000/api/videos/')
      .then(response => {
        setVideos(response.data);
        setLoading(false);
      })
      .catch(error => {
        console.error('Ошибка загрузки видео:', error);
        setLoading(false);
      });
  }, []);

  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '60vh' }}>
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: 48, marginBottom: 16 }}>🎬</div>
          <p>Загрузка видео...</p>
        </div>
      </div>
    );
  }

  return (
    <div style={{ maxWidth: 1400, margin: '0 auto', padding: '0 20px' }}>
      {/* Hero секция */}
      <div style={{
        textAlign: 'center',
        padding: '48px 32px',
        marginBottom: 32,
        background: '#fff',
        borderRadius: 16,
        boxShadow: '0 2px 8px rgba(0,0,0,0.04)'
      }}>
        <h1 style={{ fontSize: 'clamp(32px, 5vw, 48px)', fontWeight: 700, marginBottom: 12 }}>
          Видеоплатформа
        </h1>
        <p style={{ fontSize: 18, color: '#6c757d' }}>
          Смотрите, загружайте и делитесь видео
        </p>
      </div>

      {videos.length === 0 ? (
        <div style={{ textAlign: 'center', padding: 64, background: '#fff', borderRadius: 16 }}>
          <div style={{ fontSize: 64, marginBottom: 20 }}>📭</div>
          <p style={{ fontSize: 18, marginBottom: 24 }}>Пока нет видео</p>
          <Link to="/upload" style={{
            background: '#4361ee',
            color: 'white',
            padding: '12px 24px',
            borderRadius: 12,
            textDecoration: 'none'
          }}>
            + Загрузить первое видео
          </Link>
        </div>
      ) : (
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))',
          gap: 24
        }}>
          {videos.map(video => (
            <Link 
              to={`/video/${video.id}`} 
              key={video.id} 
              style={{ textDecoration: 'none' }}
            >
              <div style={{
                background: '#fff',
                borderRadius: 16,
                overflow: 'hidden',
                boxShadow: '0 2px 8px rgba(0,0,0,0.04)',
                transition: 'transform 0.2s, box-shadow 0.2s',
                cursor: 'pointer'
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.transform = 'translateY(-4px)';
                e.currentTarget.style.boxShadow = '0 12px 28px rgba(0,0,0,0.1)';
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.transform = 'translateY(0)';
                e.currentTarget.style.boxShadow = '0 2px 8px rgba(0,0,0,0.04)';
              }}>
                
                {/* ПРЕВЬЮ - красивая градиентная иконка */}
                <div style={{
                  width: '100%',
                  aspectRatio: '16/9',
                  background: `linear-gradient(135deg, ${video.id % 2 === 0 ? '#667eea' : '#764ba2'} 0%, #f093fb 100%)`,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: 56,
                  color: 'white'
                }}>
                  🎬
                </div>
                
                {/* Информация */}
                <div style={{ padding: '12px 16px 16px' }}>
                  <h3 style={{
                    fontSize: 16,
                    fontWeight: 600,
                    color: '#1a1a1a',
                    marginBottom: 6,
                    display: '-webkit-box',
                    WebkitLineClamp: 2,
                    WebkitBoxOrient: 'vertical',
                    overflow: 'hidden',
                    lineHeight: 1.4
                  }}>
                    {video.title}
                  </h3>
                  <p style={{ fontSize: 13, color: '#6c757d', margin: 0 }}>
                    {video.uploaded_by_name || 'Аноним'} • {video.views || 0} просмотров
                  </p>
                </div>
              </div>
            </Link>
          ))}
        </div>
      )}
    </div>
  );
}

export default HomePage;
